// File: VersionsDemo.java — showcases features from Java 8 through 21
// Run on Java 21+: javac VersionsDemo.java && java VersionsDemo
import java.util.*;
import java.util.stream.*;

public class VersionsDemo {

  // Java 16+ — record
  record Person(String name, int age) {}

  // Java 17+ — sealed hierarchy
  sealed interface Shape permits Circle, Square {}
  record Circle(double r) implements Shape {}
  record Square(double s) implements Shape {}

  public static void main(String[] args) {
    // Java 8 — lambda + streams + Optional
    List<Person> people = List.of(
      new Person("Ada", 34),
      new Person("Ben", 17),
      new Person("Cara", 22)
    );
    List<String> adults = people.stream()
        .filter(p -> p.age() >= 18)
        .map(Person::name)
        .toList();                        // Java 16+ — Stream.toList()
    System.out.println(adults);           // [Ada, Cara]

    // Java 10+ — var inference
    var byAge = people.stream().sorted(Comparator.comparingInt(Person::age)).toList();
    System.out.println(byAge);

    // Java 14+ — switch expression
    Person p = people.get(0);
    String bucket = switch (p.age() / 10) {
      case 0, 1 -> "minor";
      case 2    -> "twenties";
      case 3    -> "thirties";
      default   -> "older";
    };
    System.out.println(bucket);

    // Java 15+ — text blocks
    String json = """
        {
          "name": "Ada",
          "age": 34
        }
        """;
    System.out.println(json);

    // Java 21 — pattern-matching switch + record deconstruction
    Shape sh = new Circle(2);
    double area = switch (sh) {
      case Circle(double r)   -> Math.PI * r * r;
      case Square(double s)   -> s * s;
    };
    System.out.printf("area=%.2f%n", area);

    // Java 21 — sequenced collections
    List<Integer> ints = new ArrayList<>(List.of(1, 2, 3));
    ints.addFirst(0);         // sequenced-collection method
    ints.addLast(4);
    System.out.println(ints); // [0, 1, 2, 3, 4]
  }
}

// Output:
//   [Ada, Cara]
//   [Person[name=Ben, age=17], Person[name=Cara, age=22], Person[name=Ada, age=34]]
//   thirties
//   {"name":"Ada","age":34}   (approximately)
//   area=12.57
//   [0, 1, 2, 3, 4]
